#include<bits/stdc++.h>
using namespace std;
double len,slen,ans;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        double x;
        scanf("%lf",&x);
        ans=ans+(3*slen+3*len+1)*x;
        slen=(slen+2*len+1)*x;
        len=(len+1)*x;
    }
    printf("%.1lf",ans);
    return 0;
}
